import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;
import io.github.hectorvent.floci.core.common.RegionResolver;
import io.github.hectorvent.floci.core.storage.InMemoryStorage;
import io.github.hectorvent.floci.services.cognito.CognitoJsonHandler;
import io.github.hectorvent.floci.services.cognito.CognitoService;

public class CognitoListClientsRuntimeCheck {
    public static void main(String[] args) {
        ObjectMapper mapper = new ObjectMapper();
        CognitoService service = new CognitoService(
                new InMemoryStorage<>(),
                new InMemoryStorage<>(),
                new InMemoryStorage<>(),
                new InMemoryStorage<>(),
                new InMemoryStorage<>(),
                "http://localhost:4566",
                new RegionResolver("us-east-1", "000000000000")
        );
        CognitoJsonHandler handler = new CognitoJsonHandler(service, mapper);

        ObjectNode poolReq = mapper.createObjectNode();
        poolReq.put("PoolName", "list-client-shape");
        JsonNode poolBody = (JsonNode) handler.handle("CreateUserPool", poolReq, "us-east-1").getEntity();
        String userPoolId = poolBody.path("UserPool").path("Id").asText();

        ObjectNode clientReq = mapper.createObjectNode();
        clientReq.put("UserPoolId", userPoolId);
        clientReq.put("ClientName", "rich-client");
        clientReq.put("GenerateSecret", true);
        clientReq.put("AllowedOAuthFlowsUserPoolClient", true);
        clientReq.putArray("AllowedOAuthFlows").add("client_credentials");
        clientReq.putArray("AllowedOAuthScopes").add("scope/read");
        JsonNode createBody = (JsonNode) handler.handle("CreateUserPoolClient", clientReq, "us-east-1").getEntity();
        String clientId = createBody.path("UserPoolClient").path("ClientId").asText();

        ObjectNode listReq = mapper.createObjectNode();
        listReq.put("UserPoolId", userPoolId);
        JsonNode listBody = (JsonNode) handler.handle("ListUserPoolClients", listReq, "us-east-1").getEntity();
        JsonNode listed = listBody.path("UserPoolClients").get(0);
        if (listed.size() != 3 || !listed.has("ClientId") || !listed.has("ClientName") || !listed.has("UserPoolId")) {
            throw new AssertionError("ListUserPoolClients returned unexpected fields: " + listed);
        }
        for (String field : new String[] {"ClientSecret", "GenerateSecret", "AllowedOAuthFlowsUserPoolClient", "AllowedOAuthFlows", "AllowedOAuthScopes", "CreationDate", "LastModifiedDate"}) {
            if (listed.has(field)) {
                throw new AssertionError("ListUserPoolClients leaked " + field + ": " + listed);
            }
        }

        ObjectNode describeReq = mapper.createObjectNode();
        describeReq.put("UserPoolId", userPoolId);
        describeReq.put("ClientId", clientId);
        JsonNode describeBody = (JsonNode) handler.handle("DescribeUserPoolClient", describeReq, "us-east-1").getEntity();
        JsonNode described = describeBody.path("UserPoolClient");
        if (!described.has("ClientSecret") || !described.has("AllowedOAuthFlows") || !described.has("CreationDate")) {
            throw new AssertionError("DescribeUserPoolClient lost rich fields: " + described);
        }

        System.out.println("PASS: runtime list response is summary-only and describe remains rich.");
    }
}
